DROP TABLE IF EXISTS `calendar_activities`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `calendar_activities` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `act_key` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  `schedule_weekdays` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '0=周日..6=周六，逗号分隔',
  `schedule_start` time NOT NULL,
  `schedule_end` time NOT NULL,
  `schedule_start_2` time DEFAULT NULL COMMENT '第二段开始（如英雄大会第二场）',
  `schedule_end_2` time DEFAULT NULL COMMENT '第二段结束',
  `pin_early_minutes` int unsigned NOT NULL DEFAULT '30',
  `stars` tinyint unsigned NOT NULL DEFAULT '4',
  `wukai_rank` int NOT NULL DEFAULT '50',
  `sort_order` int NOT NULL DEFAULT '50',
  `month_week` tinyint unsigned DEFAULT NULL COMMENT '当月第几个「锚定星期」；NULL=仅按 weekday',
  `month_anchor_weekday` tinyint unsigned DEFAULT NULL COMMENT '与 month_week：0=周日..6=周六；月度门派闯关等为0，双龙为6',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ux_cal_act_key` (`act_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
